package com.trademaster.ims.mobile.support.controller;
import com.trademaster.ims.mobile.auth.security.CustomerAuthentication;import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.support.dto.SupportDtos.*;import com.trademaster.ims.mobile.support.service.CustomerSupportService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/mobile/v1/support/tickets")public class CustomerSupportController{private final CustomerSupportService s;public CustomerSupportController(CustomerSupportService s){this.s=s;}@GetMapping List<TicketSummary>list(Authentication a){return s.list(id(a));}@PostMapping @ResponseStatus(HttpStatus.CREATED)TicketDetail create(Authentication a,@Valid @RequestBody CreateTicketRequest q){return s.create(id(a),q);}@GetMapping("/{ticketNumber}")TicketDetail detail(Authentication a,@PathVariable String ticketNumber){return s.detail(id(a),ticketNumber);}@PostMapping("/{ticketNumber}/messages")TicketDetail reply(Authentication a,@PathVariable String ticketNumber,@Valid @RequestBody AddMessageRequest q){return s.reply(id(a),ticketNumber,q);}@PostMapping("/{ticketNumber}/close")TicketDetail close(Authentication a,@PathVariable String ticketNumber){return s.close(id(a),ticketNumber);}private long id(Authentication a){if(a instanceof CustomerAuthentication c)return c.accountId();throw new CustomerAuthException(HttpStatus.UNAUTHORIZED,"AUTHENTICATION_REQUIRED","Authentication is required.");}}